export function getEmbeddedComponent(path) {
    const clean = String(path || '').trim().replace(/^\//, '');
    return LAYOUT_COMPONENTS[clean] || LAYOUT_COMPONENTS[`components/${clean.split('/').pop()}`] || null;
}
